import {
    useEffect,
    useState
} from "react";


function AdminDashboard() {

    const [complaints, setComplaints] =
        useState([]);

    const username =
        localStorage.getItem("username");


    const fetchComplaints = () => {

        fetch(
            "http://127.0.0.1:8000/complaints"
        )
        .then(res => res.json())
        .then(data => {

            setComplaints(data);
        });
    };


    useEffect(() => {

        fetchComplaints();

    }, []);


    const updateStatus = async (
        complaintId,
        status
    ) => {

        await fetch(
            `http://127.0.0.1:8000/complaints/${complaintId}?status=${status}`,
            {
                method: "PUT"
            }
        );

        fetchComplaints();
    };


    return (

        <div style={{ padding: "30px" }}>

            <h1>Admin Dashboard</h1>

            <h3>

                Welcome {username}

            </h3>

            <hr />

            <h2>Manage Complaints</h2>

            {
                complaints.map((c) => (

                    <div
                        key={c.id}
                        style={{
                            border: "1px solid black",
                            padding: "10px",
                            marginBottom: "10px"
                        }}
                    >

                        <h3>{c.title}</h3>

                        <p>

                            {c.description}

                        </p>

                        <p>

                            Status:
                            {c.status}

                        </p>

                        <button
                            onClick={() =>
                                updateStatus(
                                    c.id,
                                    "In Progress"
                                )
                            }
                        >

                            In Progress

                        </button>

                        <button
                            onClick={() =>
                                updateStatus(
                                    c.id,
                                    "Closed"
                                )
                            }
                        >

                            Closed

                        </button>

                    </div>
                ))
            }

        </div>
    );
}

export default AdminDashboard;
